    public void WFiltro_Ocorrencia_ComCaracteresEspeciais_DeveProcessarCorretamente(string OcorrenciaComCaracteresEspeciais)
    {
        // Arrange
        var filtro = new FilterDiario2
        {
            Ocorrencia = OcorrenciaComCaracteresEspeciais,
            WildcardChar = '%',
            LogicalOperator = " AND "
        };
        // Act
        var resultado = _serviceS.WFiltroDiario2(filtro);
        // Assert
        resultado.Should().NotBeNull();
        resultado.Value.parametros.Should().HaveCount(1);
        var parametro = resultado.Value.parametros.First();
        parametro.Value.ToString().Should().Contain(OcorrenciaComCaracteresEspeciais);
    }

